## 4. Navigation Architecture

### Current Problems
- Single `Router` as ObservableObject with path manipulation
- `RoutableScreenKey` instantiates views directly -- tight coupling
- `BaseViewModel` reaches into `DependencyContainer.shared.resolve(Router.self)` -- ViewModels know about routing infrastructure
- No deep link support built in

### New Design: Coordinator Pattern

```swift
// MARK: - Coordinator Protocol (in DomainLayer)

protocol TradeCoordinator {
    func showBuySell(productId: Int, side: OrderSide)
    func showFullScreenChart(pair: String)
    func showPairSelector()
    func showOrders()
    func goBack()
}

// MARK: - SwiftUI Coordinator Implementation (in AppComposition)

@Observable
final class TradeCoordinatorImpl: TradeCoordinator {
    var path = NavigationPath()
    var sheet: TradeSheet?

    private let factory: TradeFeatureFactory

    enum Destination: Hashable {
        case fullScreenChart(pair: String)
        case orders
    }

    enum TradeSheet: Identifiable {
        case buySell(productId: Int, side: OrderSide)
        case pairSelector

        var id: String {
            switch self {
            case .buySell(let id, let side): return "buySell-\(id)-\(side)"
            case .pairSelector: return "pairSelector"
            }
        }
    }

    func showBuySell(productId: Int, side: OrderSide) {
        sheet = .buySell(productId: productId, side: side)
    }

    func showFullScreenChart(pair: String) {
        path.append(Destination.fullScreenChart(pair: pair))
    }

    func showPairSelector() {
        sheet = .pairSelector
    }

    func showOrders() {
        path.append(Destination.orders)
    }

    func goBack() {
        if !path.isEmpty { path.removeLast() }
    }
}

// MARK: - Coordinator View

struct TradeCoordinatorView: View {
    @State private var coordinator: TradeCoordinatorImpl
    private let factory: TradeFeatureFactory

    var body: some View {
        NavigationStack(path: $coordinator.path) {
            TradeView(viewModel: factory.makeTradeViewModel())
                .navigationDestination(for: TradeCoordinatorImpl.Destination.self) { dest in
                    switch dest {
                    case .fullScreenChart(let pair):
                        FullScreenChartView(pair: pair)
                    case .orders:
                        OrdersView(viewModel: factory.makeOrdersViewModel())
                    }
                }
        }
        .sheet(item: $coordinator.sheet) { sheet in
            switch sheet {
            case .buySell(let productId, let side):
                SpotBuySellView(viewModel: factory.makeSpotBuySellViewModel(
                    productId: productId, side: side
                ))
            case .pairSelector:
                MarketSpotPairSelectView(viewModel: factory.makePairSelectViewModel())
            }
        }
    }
}
```

