## 5. Networking Layer

### Current Problems
- `Endpoint<T>` uses `[String: Any]?` for body -- not type-safe
- `URLCache.shared.removeAllCachedResponses()` called on EVERY request
- `AnyPublisherBox` type-erased cache is fragile
- Direct Alamofire coupling throughout
- WebSocket and REST are separate hierarchies with no shared error handling

### New Design

```swift
// MARK: - NetworkService Protocol (in NetworkKit)

protocol NetworkService: Sendable {
    func request<T: Decodable>(_ endpoint: APIEndpoint) async throws -> T
    func request(_ endpoint: APIEndpoint) async throws  // void response
    func upload<T: Decodable>(_ endpoint: APIEndpoint, data: Data) async throws -> T
}

// MARK: - APIEndpoint (type-safe)

struct APIEndpoint: Sendable {
    let method: HTTPMethod
    let path: String
    let query: [String: String]?
    let body: (any Encodable & Sendable)?
    let headers: [String: String]
    let requiresAuth: Bool

    static func get(_ path: String, query: [String: String]? = nil) -> APIEndpoint {
        APIEndpoint(method: .get, path: path, query: query, body: nil, headers: [:], requiresAuth: true)
    }

    static func post<Body: Encodable & Sendable>(_ path: String, body: Body) -> APIEndpoint {
        APIEndpoint(method: .post, path: path, query: nil, body: body, headers: [:], requiresAuth: true)
    }
}

// MARK: - Implementation wrapping Alamofire

final class NetworkServiceImpl: NetworkService {
    private let baseURL: String
    private let session: Session
    private let tokenProvider: @Sendable () -> String?
    private let interceptors: [RequestInterceptor]

    func request<T: Decodable>(_ endpoint: APIEndpoint) async throws -> T {
        let url = baseURL + endpoint.path
        var headers = HTTPHeaders(endpoint.headers.map { HTTPHeader(name: $0.key, value: $0.value) })

        if endpoint.requiresAuth, let token = tokenProvider() {
            headers.add(.authorization(bearerToken: token))
        }

        let dataResponse = await session.request(
            url,
            method: endpoint.method.toAlamofire(),
            parameters: endpoint.body.map { AnyEncodable($0) },
            encoder: JSONParameterEncoder.default,
            headers: headers
        )
        .validate()
        .serializingDecodable(T.self)
        .response

        switch dataResponse.result {
        case .success(let value): return value
        case .failure(let error): throw NetworkError.from(error)
        }
    }
}

// MARK: - WebSocket Service Protocol

protocol WebSocketService: Sendable {
    var connectionStatus: AsyncStream<Bool> { get }
    func connect() async
    func disconnect() async
    func send<T: Encodable>(_ message: T) async throws
    func subscribe<T: Decodable>(function: String) -> AsyncThrowingStream<T, Error>
}
```

### Request Interceptors

```swift
protocol RequestInterceptorPlugin: Sendable {
    func adapt(_ request: inout URLRequest) async throws
    func retry(_ request: URLRequest, dueTo error: Error) async -> RetryDecision
}

enum RetryDecision { case retry, doNotRetry }

struct AuthTokenInterceptor: RequestInterceptorPlugin {
    let tokenRefresher: TokenRefresher

    func adapt(_ request: inout URLRequest) async throws {
        // Token injection handled by NetworkServiceImpl
    }

    func retry(_ request: URLRequest, dueTo error: Error) async -> RetryDecision {
        guard case NetworkError.unauthorized = error else { return .doNotRetry }
        do {
            try await tokenRefresher.refresh()
            return .retry
        } catch {
            return .doNotRetry
        }
    }
}
```

