## 6. State Management

### Current Problems
- `CacheSession` protocol with 60+ properties -- god object
- `AppSharedState` as another shared mutable state container
- `BaseViewModel: ObservableObject` hierarchy forces class-based ViewModels
- `TransientSession` for temporary state -- unclear lifecycle

### New Design: @Observable + Domain-Specific State Stores

```swift
// MARK: - Replace CacheSession with focused stores

@Observable
final class SessionStore: @unchecked Sendable {
    private(set) var accessToken: String?
    private(set) var userId: Int?
    private(set) var isAuthenticated: Bool = false

    func setAuthenticated(token: String, userId: Int) {
        self.accessToken = token
        self.userId = userId
        self.isAuthenticated = true
    }

    func clear() {
        accessToken = nil
        userId = nil
        isAuthenticated = false
    }
}

@Observable
final class UserProfileStore {
    private(set) var user: User?
    private(set) var kycStatus: KYCStatus?
    private(set) var accountStatus: AccountStatus?
}

@Observable
final class MarketDataStore {
    private(set) var instruments: [Instrument] = []
    private(set) var level1Summaries: [Int: Level1Summary] = [:]  // keyed by instrumentId
    private(set) var products: [Product] = []
}

@Observable
final class WalletStore {
    private(set) var positions: [AccountPosition] = []
    private(set) var cryptoAssets: [CryptoAsset] = []
}
```

**Pattern:** Each store is injected into ViewModels that need it. No global singleton access. ViewModels use `@Observable` (iOS 17+) instead of `ObservableObject`, eliminating `@Published` boilerplate.

### State Flow

```
User Action -> ViewModel method -> UseCase.execute() -> Repository -> Network
                                        |
                                        v
                                 Store.update() <- ViewModel reads from Store
                                        |
                                        v
                                   @Observable triggers SwiftUI view update
```

