## 7. Error Handling Strategy

### Current Problems
- `ApiError` enum mixed with HTTP codes, network errors, and business errors
- `BaseViewModel.handleError` is a 70-line switch with UI logic
- Force-unwraps (`!`) throughout DI resolution
- Errors silently swallowed in some Combine chains

### New Design: Layered Error Types

```swift
// MARK: - DomainLayer errors

enum AppError: Error, Equatable {
    case network(NetworkError)
    case business(BusinessError)
    case validation(String)
    case unknown(String)
}

enum NetworkError: Error, Equatable {
    case noConnection
    case timeout
    case unauthorized
    case serverError(statusCode: Int, apiId: String?)
    case decodingFailed(String)
}

enum BusinessError: Error, Equatable {
    case kycRequired
    case accountFrozen(FreezeType)
    case insufficientBalance
    case withdrawalLimitExceeded
    case custom(code: String, message: String)
}

// MARK: - Error Presentation (in CoreUI)

protocol ErrorPresenter {
    func present(error: AppError)
}

struct DefaultErrorPresenter: ErrorPresenter {
    let dialogService: DialogService

    func present(error: AppError) {
        switch error {
        case .network(.noConnection):
            dialogService.showAlert(title: "No Connection", message: "Check your internet connection.")
        case .network(.timeout):
            dialogService.showAlert(title: "Timeout", message: "Request timed out. Please try again.")
        case .network(.serverError(let code, let apiId)):
            let tag = apiId.map { "[BE\($0):\(code)]" } ?? "[BE:\(code)]"
            dialogService.showAlert(title: "Something went wrong", message: tag)
        case .business(.kycRequired):
            dialogService.showKYCAlert()
        case .business(.accountFrozen(let type)):
            dialogService.showFrozenAlert(type: type)
        default:
            dialogService.showAlert(title: "Error", message: error.localizedDescription)
        }
    }
}
```

### Logging Pipeline

```swift
// MARK: - Logging (in SharedKit)

protocol AppLogger: Sendable {
    func info(_ message: String, metadata: [String: String])
    func error(_ message: String, error: Error?, metadata: [String: String])
    func breadcrumb(_ message: String)
}

// Implementation wraps Datadog + Crashlytics (in main app target)
struct CompositeLogger: AppLogger {
    let datadogLogger: DatadogLogger
    let crashlyticsLogger: CrashlyticsLogger

    func error(_ message: String, error: Error?, metadata: [String: String]) {
        datadogLogger.error(message, error: error, metadata: metadata)
        crashlyticsLogger.log(message)
        if let error { crashlyticsLogger.record(error: error) }
    }
}
```

