## 8. Testing Architecture

### Layer Testing Strategy

| Layer | What to Test | What to Mock | Tool |
|-------|-------------|-------------|------|
| **DomainLayer** | Use case logic, entity behavior | Repository protocols | XCTest, no frameworks needed |
| **DataLayer** | DTO mapping, repository caching logic | NetworkService protocol | XCTest + mock NetworkService |
| **Presentation** | ViewModel state transitions, user actions | Use case protocols, Coordinator | XCTest + @Observable assertions |
| **NetworkKit** | Request building, error mapping | URLProtocol for integration | XCTest |
| **E2E** | Critical flows (login, trade, deposit) | Nothing (real backend or test server) | XCUITest |

### Example Test

```swift
// TradeViewModelTests.swift
@MainActor
final class TradeViewModelTests: XCTestCase {
    func test_onAppear_loadsInstruments() async {
        let mockInstruments = [Instrument.stub(instrumentId: 1)]
        let getInstruments = MockGetAllowedInstrumentsUseCase(result: mockInstruments)
        let coordinator = MockTradeCoordinator()

        let sut = TradeViewModel(
            getInstruments: getInstruments,
            subscribeOrderBook: MockSubscribeOrderBookUseCase(),
            coordinator: coordinator
        )

        await sut.onAppear()

        XCTAssertEqual(sut.selectedInstrument, mockInstruments.first)
        XCTAssertFalse(sut.isLoading)
    }

    func test_onBuyTap_coordinatesToBuySell() {
        let coordinator = MockTradeCoordinator()
        let sut = TradeViewModel(
            getInstruments: MockGetAllowedInstrumentsUseCase(result: [.stub()]),
            subscribeOrderBook: MockSubscribeOrderBookUseCase(),
            coordinator: coordinator
        )
        sut.selectedInstrument = .stub(instrumentId: 42)

        sut.onBuyTap()

        XCTAssertEqual(coordinator.lastBuySellProductId, 42)
        XCTAssertEqual(coordinator.lastBuySellSide, .buy)
    }
}

// MockGetAllowedInstrumentsUseCase.swift (in test target)
struct MockGetAllowedInstrumentsUseCase: GetAllowedInstrumentsUseCase {
    let result: [Instrument]

    func execute(forceUpdate: Bool) async throws -> [Instrument] {
        return result
    }
}
```

