### 2.3 ViewModels: ObservableObject (NOT @Observable)

**What I originally proposed:** `@Observable` (iOS 17+)

**What changes:** Stay with `ObservableObject` + `@Published` for iOS 16+ compatibility.

```swift
// TradeViewModel using ObservableObject + swift-dependencies + swift-sharing
final class TradeViewModel: ObservableObject {
    @Dependency(\.instrumentClient) private var instrumentClient
    @Dependency(\.webSocketClient) private var webSocketClient

    @Shared(.inMemory("selectedTradeInstrument")) var selectedInstrument: Instrument?
    @Shared(.inMemory("orderBooks")) var orderBooks: [Int: [OrderBook]] = [:]

    @Published var latestPrice: String = "0.00"
    @Published var isLoading = false
    @Published var error: AppError?

    private var orderBookTask: Task<Void, Never>?

    func onAppear() {
        Task { await loadInstruments() }
    }

    func onDisappear() {
        orderBookTask?.cancel()
    }

    private func loadInstruments() async {
        isLoading = true
        defer { isLoading = false }
        do {
            let instruments = try await instrumentClient.getAllowed()
            await MainActor.run {
                $selectedInstrument.withLock { $0 = instruments.first }
            }
        } catch {
            self.error = AppError(from: error)
        }
    }
}
```

